esqlQuery.esql:
FROM metrics-traefik.otel-*
// Limit to Go runtime goroutine gauge
| WHERE go_goroutines IS NOT NULL
// Take max goroutine count in window (gauge)
| STATS goroutines = MAX(go_goroutines)
// Alert when goroutines exceed threshold; tune for typical baseline (e.g. 500-2000)
| WHERE goroutines > 2000
